VALUES
  ('optician-moex-00329', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關配戴硬式透氧散光隱形眼鏡所產生的誘發性散光（Inducedastigmatism），下列敘述何者正確？', '["硬式透氧散光隱形眼鏡所產生的誘發性散光的高低，與鏡片本身的原料（material）沒有關係", "誘發性散光主要是因為隱形眼鏡及淚水所產生的淚鏡系統（tearlenssystem）中，環形後光學區（toroidal backopticzone）因為兩個表面不同折射率結合所產生的", "計算的方式為：誘發性散光＝眼鏡的散光度數－角膜散光度數", "未矯正之散光即稱為誘發性散光，為水晶體所引起的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00330', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '根據Bennett&Henry教科書，傳統角膜弧度儀（keratometer）可用來測量角膜中央直徑約：', '["1.0mm", "2.0mm", "3.0mm", "4.0mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00331', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列那一個參數的變化對於改變軟式隱形眼鏡的矢深會最大？', '["鏡片直徑", "基弧", "中心厚度", "鏡片材料"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00332', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '驗配硬式透氧隱形眼鏡（RGPlens）試片為-3.00DS，戴鏡驗光（overrefraction）眼鏡度數為-6.00DS，頂點 距離為12mm，所需隱形眼鏡度數為何？', '["-8.25DS", "-8.50DS", "-8.75DS", "-9.00DS"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00333', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種情形會產生正淚鏡1.00D？', '["角膜弧度7.80mm，硬式鏡片基弧8.00mm", "角膜弧度7.80mm，硬式鏡片基弧7.90mm", "角膜弧度7.80mm，硬式鏡片基弧7.70mm", "角膜弧度7.80mm，硬式鏡片基弧7.60mm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00334', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '對於軟式隱形眼鏡的配戴評估，下列何者錯誤？', '["要確認隱形眼鏡光學區是否有完全覆蓋到瞳孔，可採用視網膜檢影鏡鏡檢法（retinoscopy）檢查", "在眨眼（blinking）後鏡片向下移位1.5mm，表示配適太陡（steep），鏡片基弧須要修正縮小變平（flat）", "軟式隱形眼鏡的配適剛開始時舒適無異物感，但在長時間的配戴後眼會微疼痛及感覺疲倦，則可能是隱 形眼鏡配適太緊（tight）", "鏡片需完全覆蓋角膜，且鏡片直徑（overalllensdiameter）至少須大於輪部1.5mm以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00335', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '使用RGP試戴片：度數-6.00D／基弧7.75mm／鏡片直徑9.4mm，戴鏡驗光最佳視力1.0時的度數為 -4.50DS，插片頂點距離為12mm。開立配鏡處方時，想更改基弧為7.85mm，則此訂片的隱形眼鏡屈 光度數應為何？', '["-9.25DS", "-9.50DS", "-9.75DS", "-10.00DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00336', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關裂隙燈顯微鏡的間接照明法（indirectillumination），下列敘述何者錯誤？', '["光線照射在虹彩上，反射回來觀察到角膜組織為其中一種方法", "可用來觀察角膜新生血管及水晶體的微細變化", "背面反射照明（retroillumination）是其中一種方法", "可觀察角膜內皮細胞多狀症（polymegathism）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00337', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '患者角膜內皮細胞多狀症（polymegathism）之嚴重程度至少大於第幾級時，較能透過裂隙燈觀察到？', '["第0級", "第1級", "第2級", "第3級"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00338', 'optician', 'optician-moex-113-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '角膜上緣表皮弧形病灶（superior epithelialarcuatelesions）為戴隱形眼鏡者在角膜上緣近輪部處產生一弧 形的表皮破損，下列敘述何者錯誤？', '["和微生物感染有關", "和鏡片的機械性摩擦有關", "眼皮壓力較大者如亞洲人較易發生", "矽水膠鏡片比水膠鏡片容易發生"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "9ce60e79e695", "answer_pdf_sha1": "d7313869c418", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
